oxy_webhelp_navlinks = {"rsc_security-d27243e10844":{"topics":[{"title":"IP allowlist","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> administrators can specify IPv4 addresses for the IP allowlist.             <span class=\"ph\">RSC<\/span> blocks unauthorized login attempts and unauthenticated API calls         that originate from addresses that are not on the allowlist.<\/p>","href":"saas\/common\/ip_allowlist.html","attributes":{"data-id":"ip_allowlist"},"menu":{"hasChildren":false},"tocID":"ip_allowlist-d27243e10857","next":"ip_allowlist-d27243e10857"},{"title":"Authentication","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">Rubrik Security Cloud<\/span> authentication restricts access to a specified set of         users.<\/p>","href":"saas\/common\/saas_authentication.html","attributes":{"data-id":"saas_authentication"},"menu":{"hasChildren":false},"tocID":"saas_authentication-d27243e10929","next":"saas_authentication-d27243e10929"},{"title":"Certificate management","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> Certificate Management provides a centralized dashboard to manage         certificates across all connected Rubrik clusters and for <span class=\"ph\">RSC<\/span>         workflows.<\/p>","href":"saas\/rsc_certificate_management.html","attributes":{"data-id":"rsc_certificate_management"},"menu":{"hasChildren":false},"tocID":"rsc_certificate_management-d27243e11103","next":"rsc_certificate_management-d27243e11103"},{"title":"Encryption management","shortdesc":"<p class=\"shortdesc\">With the encryption management feature in <span class=\"ph\">RSC<\/span>, you can view         information about data-at-rest encryption for the Rubrik clusters and archives, access to         your Key Management Services, and enhance data security through automated key rotation every         30 days.<\/p>","href":"saas\/rsc_encryption_management.html","attributes":{"data-id":"rsc_encryption_management"},"menu":{"hasChildren":false},"tocID":"rsc_encryption_management-d27243e11216","next":"rsc_encryption_management-d27243e11216"},{"title":"User account lockout","shortdesc":"<p class=\"shortdesc\">The user account lockout feature enhances system security by providing global         administrators the ability to lock and unlock user accounts. This feature also prevents         unauthorized access from brute force attacks and safeguards local user accounts by         automatically locking them after a configurable period of inactivity.<\/p>","href":"saas\/common\/user_account_lockout.html","attributes":{"data-id":"user_account_lockout"},"menu":{"hasChildren":false},"tocID":"user_account_lockout-d27243e11434","next":"user_account_lockout-d27243e11434"},{"title":"Session management","shortdesc":"<p class=\"shortdesc\">The session management feature enhances system security in the following ways: ending         inactive user sessions, ending active user sessions after a specific duration, and limiting         the number of concurrent sessions allowed for each user.<\/p>","href":"saas\/common\/session_management.html","attributes":{"data-id":"session_management"},"menu":{"hasChildren":false},"tocID":"session_management-d27243e11556","next":"session_management-d27243e11556"},{"title":"Password policy","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> administrators can enhance the security of their <span class=\"ph\">RSC<\/span> domain by using the password policy feature to configure password         complexity rules for local users.<\/p>","href":"saas\/password_policy.html","attributes":{"data-id":"password_policy"},"menu":{"hasChildren":false},"tocID":"password_policy-d27243e11623","next":"password_policy-d27243e11623"},{"title":"New device login notification","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> notifies you when a new device is used to log in to your <span class=\"ph\">RSC<\/span> account, providing details such as device name, IP address, and         location.<\/p>","href":"saas\/common\/sec_new_device_login_notification.html","attributes":{"data-id":"sec_new_device_login_notification"},"menu":{"hasChildren":false},"tocID":"sec_new_device_login_notification-d27243e11680","next":"sec_new_device_login_notification-d27243e11680"}]}};